import React, { useEffect, useState, useCallback, useMemo } from 'react';
import PropTypes from 'prop-types';
import { useTheme } from '../../contexts/ThemeContext';
import TextAnimation from '../common/TextAnimation';
import styles from './Skills.module.css';

/**
 * Skills component displays the user's technical skills with interactive visualizations.
 * It categorizes skills and provides interactive elements for the user to explore.
 * 
 * Performance optimized with:
 * - useMemo for expensive calculations
 * - useCallback for event handlers
 * - React.memo to prevent unnecessary re-renders
 */
const Skills = ({ skillsData, data }) => {
  // support old prop name 'data' used in tests
  const skills = skillsData || data;
  const { theme } = useTheme();
  const [activeCategory, setActiveCategory] = useState('all');
  const [animatedSkills, setAnimatedSkills] = useState([]);
  const [isVisible, setIsVisible] = useState(false);

  // Categories for skills (can be extracted from skillsData) - memoized
  const categories = useMemo(() => {
    return [
      'all',
      ...new Set((skills || []).map(skill => skill.category))
    ];
  }, [skills]);

  // Animate skills when they come into view
  useEffect(() => {
    const observer = new IntersectionObserver(
      ([entry]) => {
        if (entry.isIntersecting) {
          setIsVisible(true);
          observer.disconnect();
        }
      },
      { threshold: 0.2 }
    );

    const skillsSection = document.getElementById('skills-section');
    if (skillsSection) {
      observer.observe(skillsSection);
    }

    return () => {
      if (skillsSection) {
        observer.disconnect();
      }
    };
  }, []);

  // Animate skills progressively
  useEffect(() => {
    if (isVisible && skills) {
      const animationDelay = 100; // ms between each skill animation

      const timer = setTimeout(() => {
        const interval = setInterval(() => {
          setAnimatedSkills(prev => {
            if (prev.length >= skills.length) {
              clearInterval(interval);
              return prev;
            }
            return [...prev, skills[prev.length]];
          });
        }, animationDelay);

        return () => clearInterval(interval);
      }, 500); // Initial delay

      return () => clearTimeout(timer);
    }
  }, [isVisible, skills]);

  // Filter skills based on active category - memoized
  const filteredSkills = useMemo(() => {
    return activeCategory === 'all'
      ? animatedSkills
      : animatedSkills.filter(skill => skill.category === activeCategory);
  }, [activeCategory, animatedSkills]);

  // Generate a dynamic color based on skill proficiency and theme - memoized
  const getSkillColor = useCallback((proficiency) => {
    const hue = theme === 'dark' ? 200 : theme === 'cyberpunk' ? 300 : 170;
    const saturation = theme === 'cyberpunk' ? '100%' : '70%';
    const lightness = theme === 'dark' 
      ? `${40 + proficiency * 30}%`
      : theme === 'cyberpunk'
        ? `${45 + proficiency * 25}%`
        : `${30 + proficiency * 30}%`;
        
    return `hsl(${hue}, ${saturation}, ${lightness})`;
  }, [theme]);

  // Handle category change - memoized
  const handleCategoryChange = useCallback((category) => {
    setActiveCategory(category);
  }, []);

  return (
    <section 
      id="skills-section" 
      className={styles.skills}
      data-testid="skills-component"
    >
      <div className={styles.container}>
        <TextAnimation 
          text="Technical Skills" 
          className={styles.title}
          animation="fadeIn"
        />
        
        <div className={styles.categories}>
          {categories.map((category) => (
            <button
              key={category}
              className={`${styles.categoryButton} ${activeCategory === category ? styles.active : ''}`}
              onClick={() => handleCategoryChange(category)}
              data-testid={`category-${category}`}
            >
              {category.charAt(0).toUpperCase() + category.slice(1)}
            </button>
          ))}
        </div>
        
        <div className={styles.skillsGrid}>
          {filteredSkills.map((skill, index) => (
            <div 
              key={skill.name} 
              className={styles.skillItem}
              style={{
                animationDelay: `${index * 0.1}s`,
                opacity: isVisible ? 1 : 0,
                transform: isVisible ? 'translateY(0)' : 'translateY(20px)'
              }}
              data-testid={`skill-${skill.name}`}
            >
              <div className={styles.skillHeader}>
                <h3 className={styles.skillName}>{skill.name}</h3>
                <span className={styles.skillLevel}>
                  {skill.level || `${Math.round(skill.proficiency * 100)}%`}
                </span>
              </div>
              
              <div className={styles.skillBarContainer}>
                <div 
                  className={styles.skillBar}
                  style={{
                    width: `${skill.proficiency * 100}%`,
                    backgroundColor: getSkillColor(skill.proficiency)
                  }}
                />
              </div>
              
              {skill.description && (
                <p className={styles.skillDescription}>{skill.description}</p>
              )}
            </div>
          ))}
        </div>
        
        {/* Placeholder for 3D skill visualization */}
        <div className={styles.visualizationContainer} data-testid="skill-visualization-container">
          {/* SkillVisualization component will be implemented separately (T045) */}
        </div>
      </div>
    </section>
  );
};

Skills.propTypes = {
  skillsData: PropTypes.arrayOf(
    PropTypes.shape({
      name: PropTypes.string.isRequired,
      category: PropTypes.string.isRequired,
      proficiency: PropTypes.number.isRequired, // 0-1 value
      level: PropTypes.string, // Optional textual representation (e.g., "Expert")
      description: PropTypes.string,
      icon: PropTypes.string,
    })
  ).isRequired,
};

// Mock data for development
Skills.defaultProps = {
  skillsData: [
    { name: 'JavaScript', category: 'frontend', proficiency: 0.9, level: 'Expert', description: 'ES6+, TypeScript, React' },
    { name: 'React', category: 'frontend', proficiency: 0.85, level: 'Advanced', description: 'Hooks, Context, Redux' },
    { name: 'CSS/SCSS', category: 'frontend', proficiency: 0.8, level: 'Advanced', description: 'Animations, Flexbox, Grid' },
    { name: 'HTML5', category: 'frontend', proficiency: 0.9, level: 'Expert', description: 'Semantic markup, Accessibility' },
    { name: 'Node.js', category: 'backend', proficiency: 0.75, level: 'Intermediate', description: 'Express, API development' },
    { name: 'Python', category: 'backend', proficiency: 0.7, level: 'Intermediate', description: 'Django, Flask, Data analysis' },
    { name: 'GraphQL', category: 'backend', proficiency: 0.65, level: 'Intermediate', description: 'Apollo, Schema design' },
    { name: 'MongoDB', category: 'database', proficiency: 0.7, level: 'Intermediate', description: 'Schema design, Aggregation' },
    { name: 'PostgreSQL', category: 'database', proficiency: 0.65, level: 'Intermediate', description: 'Queries, Indexing' },
    { name: 'Git', category: 'tools', proficiency: 0.85, level: 'Advanced', description: 'Version control, Collaboration' },
    { name: 'Docker', category: 'tools', proficiency: 0.6, level: 'Intermediate', description: 'Containerization, Deployment' },
    { name: 'Jest', category: 'testing', proficiency: 0.75, level: 'Intermediate', description: 'Unit testing, Integration testing' },
  ],
};

// Export memoized component
export default React.memo(Skills);
